SELECT MAX(return) AS max_return
FROM market_returns
WHERE instrument_id = 123;

SELECT MAX(forecasted_return) AS max_forecasted_return
FROM return_forecasts
WHERE instrument_id = 101;

SELECT forecasted_return
FROM return_forecasts
WHERE instrument_id = 12345;

SELECT note_type, COUNT(*) AS note_count
FROM analyst_notes
GROUP BY note_type;

SELECT instrument_id, AVG(return) AS avg_return, MAX(return) AS max_return
FROM market_returns
GROUP BY instrument_id;

SELECT AVG(forecasted_return) AS avg_forecasted_return
FROM return_forecasts
WHERE instrument_id = 102;

SELECT instrument_id, MAX(forecasted_return) AS max_forecasted_return
FROM return_forecasts
GROUP BY instrument_id;
